import{_ as i,C as s,o as t,c as o,a2 as a,b as l,w as r,a as c,E as d,a3 as u}from"./chunks/framework.fDPUq4J2.js";const b=JSON.parse('{"title":"TORCH - Transfer Of Resources in Clinical Healthcare","description":"","frontmatter":{},"headers":[],"relativePath":"overview.md","filePath":"overview.md","lastUpdated":1778848696000}'),p={name:"overview.md"};function h(f,e,g,m,R,C){const n=s("Mermaid");return t(),o("div",null,[e[1]||(e[1]=a('<h1 id="torch-transfer-of-resources-in-clinical-healthcare" tabindex="-1">TORCH - Transfer Of Resources in Clinical Healthcare <a class="header-anchor" href="#torch-transfer-of-resources-in-clinical-healthcare" aria-label="Permalink to &quot;TORCH - Transfer Of Resources in Clinical Healthcare&quot;">​</a></h1><h2 id="goal" tabindex="-1">Goal <a class="header-anchor" href="#goal" aria-label="Permalink to &quot;Goal&quot;">​</a></h2><p><strong>T</strong>ransfer <strong>O</strong>f <strong>R</strong>esources in <strong>C</strong>linical <strong>H</strong>ealthcare or <strong>Torch</strong> is a project that aims to provide a service that allows the local execution of structured data extraction queries on a FHIR-server.</p><p>The main goal of TORCH is to automate the extraction of structured clinical data from FHIR servers as defined by a well defined query language the so called <a href="./crtdl/crtdl.html">Clinical Resource Transfer Definition Language (CRTDL)</a> .</p><p>This is vital inside clinical research networks, where data from multiple institutions needs to be aggregated for centralized and decentralized analysis.</p><p>Manual extraction and transformation of data is time-consuming and error-prone, especially in a decentralized scenario.</p><p>TORCH aims to solve this problem by providing a tool that can extract data based on a well-defined <strong>human-readable</strong> structure and apply consent rules to ensure consent compliance. This structure can then be used to extract data from multiple institutions in a consistent manner.</p><p>A exemplary use case based on the <a href="https://www.medizininformatik-initiative.de/en/" target="_blank" rel="noreferrer">German Medical Informatics Initiative (MII)</a>, where TORCH is used to extract data from hospital FHIR servers for a centralized analysis based on the <a href="./crtdl/crtdl.html">Clinical Resource Transfer Definition Language (CRTDL)</a> is shown below:</p>',8)),(t(),l(u,null,{default:r(()=>[d(n,{id:"mermaid-24",class:"mermaid",graph:"flowchart%20TD%0A%09R%5B%22Researcher%22%5D%0A%09FP%5B%22Feasibility%20Portal%22%5D%0A%09AP%5B%22Approval%20Authority%22%5D%0A%09DIC%5B%22Data%20Integration%20Center%22%5D%0A%09DMS%5B%22Data%20Management%20Institution%22%5D%0A%09RP%5BResearch%20Proposal%20Review%5D%0A%09T%5B%22%E2%9A%99%20TORCH%22%5D%0A%09PP%5B%22%E2%9A%99%20Post-Processing%20System%22%5D%0A%09R%20--%3E%7CResearch%20Idea%7C%20FP%0A%09FP%20--%3E%7CResearch%20Proposal%20with%20CRTDL%7C%20RP%0A%09RP%20--%3E%20AP%0A%09AP%20--%3E%7CApproved%7C%20DIC%0A%09T%20--%3E%20PP%0A%09DIC%20--%3E%7CExecute%20Data%20Extraction%7C%20T%0A%09PP%20--%3E%7CExtracted%20Data%7C%20DIC%0A%09DIC%20--%3E%7CTransfer%20Data%7C%20DMS%0A%09DMS%20--%3E%7CCentrally%20Postprocessed%20Data%7C%20R%0A"})]),fallback:r(()=>[...e[0]||(e[0]=[c(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=a('<h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><p>TORCH provides a range of features to support standardized and consent-aware data extraction:</p><ul><li><strong>Required Fields Validation</strong>: Ensures that mandatory fields defined in the CRTDL are present in the extracted resources.</li><li><strong>Consent Handling</strong>: Applies consent rules as defined in the CRTDL to guarantee compliance during data extraction.</li><li><strong>Reference Resolution</strong>: Resolves references between resources while maintaining referential integrity.</li><li><strong>Slicing and Extensions</strong>: Supports slicing and FHIR extensions to handle institution-specific resource structures.</li><li><strong>Profile Adherence</strong>: Only keeps elements from extracted resources as specified by specific FHIR profiles (see <a href="./implementation/redaction.html">Redaction</a>).</li><li><strong>FHIR Bulk Data Access</strong>: Implements the <a href="./api/api.html">FHIR Bulk Data Access</a> specification for efficient large-scale data extraction.</li><li><strong>FHIR-to-FHIR Transfer</strong>: Creates extracted data in a FHIR-compliant format ready for import into another FHIR server or further FHIR based processing - ensuring maximum interoperability.</li></ul><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><ul><li><strong>Value Sets Binding Slices</strong>: Since TORCH does not have its own terminology service, it does not support slicing by value set bindings.</li><li><strong>FHIR Version Support</strong>: TORCH currently supports only <strong>FHIR R4</strong>. Other versions (e.g., DSTU2, R5) are not supported.</li><li><strong>Configured profile support</strong>: TORCH supports the <strong>set of FHIR profiles</strong> provided at startup through configuration. In practice, TORCH uses a claim-based profile model and works with canonical profile URLs and resource profile annotations rather than fully inferring profiles from resource content at runtime (see <a href="./configuration.html">Configuration</a>).</li><li><strong>Nested Resources</strong>: TORCH does not handle <strong>deeply nested resources</strong>; they are currently treated as a single field rather than fully resolved structures.</li><li><strong>Performance Constraints</strong>: Large-scale extraction is bound by the <strong>FHIR Bulk Data Access specification</strong> and server capabilities; performance may vary depending on server implementation.</li><li><strong>Consent Complexity</strong>: Consent handling is limited to <strong>rule-based approaches defined in the CRTDL</strong>. Complex or non-standard consent models may require customization.</li><li><strong>Interoperability</strong>: TORCH ensures FHIR compliance but does not guarantee interoperability with <strong>all vendor-specific FHIR implementations</strong>.</li></ul><h2 id="license" tabindex="-1">License <a class="header-anchor" href="#license" aria-label="Permalink to &quot;License&quot;">​</a></h2><p>TORCH is licensed under the Apache License, Version 2.0. See the <a href="https://github.com/medizininformatik-initiative/torch/tree/main/LICENSE" target="_blank" rel="noreferrer">LICENSE</a> file for details.</p>',7))])}const A=i(p,[["render",h]]);export{b as __pageData,A as default};
